const{fileURLToPath:nodeFUTP,pathToFileURL:nodePTFU}=require('url');const fileURLToPath=(url)=>{if(!url)return'';return nodeFUTP(url);};const pathToFileURL=(p)=>nodePTFU(p);class URI{static parse(s){return new URI(s);}static file(s){return new URI(s);}static fileURLToPath(url){return fileURLToPath(url);}static pathToFileURL(path){return pathToFileURL(path);}constructor(u){this.scheme='file';this.path=u;}toString(){return this.scheme+'://'+this.path;}toFilePath(){return this.path?(this.path.startsWith('/')?this.path:'/'+this.path):'';}}module.exports={URI,fileURLToPath,pathToFileURL};module.exports.default={URI,fileURLToPath,pathToFileURL};